		multi_endlevel_score();
	else
#endif
		DoEndLevelScoreGlitz(0);

	if (Current_mission_num == 0 && !((Game_mode & GM_MULTI) && !(Game_mode & GM_MULTI_COOP)))
	{
		WINDOS(
			dd_gr_set_current_canvas(NULL),
			gr_set_current_canvas(NULL)
		);
		WINDOS(
			dd_gr_clear_canvas(BM_XRGB(0, 0, 0)),
