void bash_to_shield(int i, const char* s)
{
#ifdef USE_OX_BRIDGE
	if (cd_ox_is_ready()) {
		/* Register gameseq effects on first call */
		static int gs_reg = 0;
		if (!gs_reg) {
			gs_reg = 1;
			cd_ox_register_gameseq_effects(
				/* fetch_bash_data: returns [obj_id, shield_vclip_num, shield_frame_time] */
				[](int objnum, int32_t* out) {
					out[0] = Objects[objnum].id;
					int shield_vclip = Powerup_info[POW_SHIELD_BOOST].vclip_num;
					out[1] = shield_vclip;
					out[2] = Vclip[shield_vclip].frame_time;
				},
				/* write_bash_data: packed = [objnum, old_type, new_id, vclip_num, frametime] */
				[](const int32_t* packed, int len) {
					if (len < 5) return;
					int objnum = packed[0];
					int old_type = packed[1];
					PowerupsInMine[old_type] = MaxPowerupsAllowed[old_type] = 0;
					Objects[objnum].id = packed[2];
					Objects[objnum].rtype.vclip_info.vclip_num = packed[3];
					Objects[objnum].rtype.vclip_info.frametime = packed[4];
				},
				/* fetch_stuck_objects_data: [num_stuck, (wallnum, objnum, obj_type, obj_id) x 32] */
				[](int32_t* out, int* out_len) {
					out[0] = Num_stuck_objects;
					for (int i = 0; i < MAX_STUCK_OBJECTS; i++) {
						int base = 1 + i * 4;
						out[base + 0] = Stuck_objects[i].wallnum;
						out[base + 1] = Stuck_objects[i].objnum;
						if (Stuck_objects[i].wallnum != -1) {
							out[base + 2] = Objects[Stuck_objects[i].objnum].type;
							out[base + 3] = Objects[Stuck_objects[i].objnum].id;
						} else {
							out[base + 2] = 0;
							out[base + 3] = 0;
						}
					}
				},
				/* write_clear_stuck_objects: packed = [n_flares, objnum_0..n-1, new_num_stuck] */
				[](const int32_t* packed, int len) {
					if (len < 2) return;
					int n_flares = packed[0];
					for (int j = 0; j < n_flares; j++)
						Objects[packed[j + 1]].lifeleft = F1_0 / 8;
					/* Clear all stuck objects */
					for (int i = 0; i < MAX_STUCK_OBJECTS; i++)
						Stuck_objects[i].wallnum = -1;
					Num_stuck_objects = packed[len - 1];
				});
		}
		cd_ox_bash_to_shield(i);
		return;
	}
#endif
	int type = Objects[i].id;

	mprintf((0, "Bashing %s object #%i to shield.\n", s, i));

	PowerupsInMine[type] = MaxPowerupsAllowed[type] = 0;

	Objects[i].id = POW_SHIELD_BOOST;
	Objects[i].rtype.vclip_info.vclip_num = Powerup_info[Objects[i].id].vclip_num;
	Objects[i].rtype.vclip_info.frametime = Vclip[Objects[i].rtype.vclip_info.vclip_num].frame_time;
}

