	if (!(Game_mode & GM_HOARD))
	{
		Int3(); // Get Leighton, something bad has happened.
		return;
	}

	switch (whichplay)
	{
	case 0: // Smacked!
		HUD_init_message("Ouch! %s has been smacked by %s!", Players[dpnum].callsign, Players[spnum].callsign);
